#include <bits/stdc++.h>
using namespace std;
string s;
int len;
long long n;
char dfs(int f,long long p,long long len){
    if(f==1)
        return s[p];
    else if(p>len/2)
        return dfs(f-1,(p==len/2+1?len/2:p-1-len/2),len/2);
    else
    	return dfs(f-1,p,len/2);
}
int main(){
    cin>>s>>n;
    len=s.size(),s=" "+s;
    int cnt=1;
    long long tmp=len;
    while(tmp<n)
        tmp*=2,cnt++;
    cout<<dfs(cnt,n,tmp);
    return 0;
}
